content.content:
body { font-family: system-ui, sans-serif; margin: 40px; }
.card { max-width: 520px; padding: 16px; border: 1px solid #ddd; border-radius: 12px; }
label { display: grid; gap: 6px; margin-top: 12px; }
input { padding: 10px 12px; border: 1px solid #ddd; border-radius: 10px; }
button { margin-top: 14px; padding: 10px 12px; cursor: pointer; }
.muted { color: #666; }
.saida { margin-top: 16px; padding: 12px; border: 1px dashed #aaa; border-radius: 10px; }

'use strict';

function assertEl(selector) {
  const el = document.querySelector(selector);
  if (el === null) console.error(`[validacao] elemento não encontrado: ${selector}`);
  return el;
}

const form = assertEl('#form');
const elNome = assertEl('#nome');
const elIdade = assertEl('#idade');
const elDesconto = assertEl('#desconto');
const elSaida = assertEl('#saida');

const hasDom = Boolean(form && elNome && elIdade && elDesconto && elSaida);
if (!hasDom) console.warn('[validacao] inicialização abortada por DOM incompleto.');

function parseNumeroObrigatorio(raw) {
  const s = String(raw).trim();
  if (s.length === 0) return { ok: false, reason: 'vazio' };
  const n = Number(s);
  if (Number.isNaN(n)) return { ok: false, reason: 'nan' };
  return { ok: true, value: n };
}

function parseNumeroOpcional(raw, fallback) {
  const s = String(raw).trim();
  if (s.length === 0) return { ok: true, value: fallback };
  const n = Number(s);
  if (Number.isNaN(n)) return { ok: false, reason: 'nan' };
  return { ok: true, value: n };
}

function validarNome(nome) {
  const n = String(nome).trim();
  if (n.length < 2) return { ok: false, msg: 'Nome deve ter pelo menos 2 caracteres.' };
  return { ok: true, value: n };
}

function validarIdade(idade) {
  if (!Number.isInteger(idade)) return { ok: false, msg: 'Idade deve ser um inteiro.' };
  if (idade < 0 || idade > 120) return { ok: false, msg: 'Idade fora da faixa (0 a 120).' };
  return { ok: true, value: idade };
}

function validarDesconto(desconto) {
  if (desconto < 0 || desconto > 80) return { ok: false, msg: 'Desconto fora da faixa (0 a 80).' };
  return { ok: true, value: desconto };
}

function renderSaida(msg) {
  elSaida.textContent = msg;
}

function onSubmit(event) {
  event.preventDefault();
  if (!hasDom) return;

  const nomeRes = validarNome(elNome.value);
  if (!nomeRes.ok) return renderSaida(`Erro: ${nomeRes.msg}`);

  const idadeParsed = parseNumeroObrigatorio(elIdade.value);
  if (!idadeParsed.ok) {
    return renderSaida(
      idadeParsed.reason === 'vazio'
        ? 'Erro: Idade é obrigatória.'
        : 'Erro: Idade inválida (não é número).'
    );
  }

  const idadeRes = validarIdade(idadeParsed.value);
  if (!idadeRes.ok) return renderSaida(`Erro: ${idadeRes.msg}`);

  const descontoParsed = parseNumeroOpcional(elDesconto.value, 0);
  if (!descontoParsed.ok) return renderSaida('Erro: Desconto inválido (não é número).');

  const descontoRes = validarDesconto(descontoParsed.value);
  if (!descontoRes.ok) return renderSaida(`Erro: ${descontoRes.msg}`);

  const nome = nomeRes.value;
  const idade = idadeRes.value;
  const desconto = descontoRes.value;

  const status = (idade >= 18) ? 'Maior de idade' : 'Menor de idade';

  // Default correto (não confundir falsy com ausência)
  const cupom = null;
  const cupomFinal = cupom ?? 'SEM-CUPOM';

  return renderSaida(
    `OK: ${nome} (${idade}) — ${status}. Desconto: ${desconto}%. Cupom: ${cupomFinal}.`
  );
}

if (hasDom) {
  form.addEventListener('submit', onSubmit);
  console.log('[validacao] pronto');
}
